'use strict';

const path      = require('path');
const fs        = require('fs');
const os        = require('os');
const { findJsonlFiles } = require('./log-scanner');
const { parseNewLines }  = require('./log-parser');
const wal                = require('./wal');
const { sendPending }    = require('./sender');
const { CONFIG_DIR }     = require('./config');

const PID_FILE = path.join(CONFIG_DIR, 'daemon.pid');

// Priority: env var set by parent spawn → config saved at postinstall → cwd fallback
const PROJECT_PATH = process.env.AICP_PROJECT_PATH
  || (() => { try { return require('./config').load()?.projectPath || ''; } catch { return ''; } })()
  || process.cwd();

async function tick() {
  const files = findJsonlFiles(PROJECT_PATH);
  let total = 0;
  for (const f of files) {
    const records = parseNewLines(f);
    if (records.length) {
      wal.append(records);
      total += records.length;
    }
  }
  if (total > 0) console.log(`[daemon] Parsed ${total} new usage records from ${files.length} files`);
  await sendPending();
}

function readPid() {
  try { return parseInt(fs.readFileSync(PID_FILE, 'utf8'), 10); } catch { return null; }
}

function start() {
  const cwd = process.cwd();
  // Only update saved projectPath when run from a real project dir (not a system dir)
  const isProject = fs.existsSync(path.join(cwd, 'package.json')) || fs.existsSync(path.join(cwd, '.git'));
  if (isProject) {
    try {
      const cfg = require('./config').load() || {};
      require('./config').save({ ...cfg, projectPath: cwd });
    } catch {}
  }

  // Resolved path to pass to the worker (env var survives detach)
  const projectPath = (isProject ? cwd : null) || PROJECT_PATH;

  const existingPid = readPid();
  if (existingPid) {
    try {
      process.kill(existingPid, 0);
      console.log(`[daemon] Already running (pid ${existingPid}), tracking: ${projectPath}`);
      return;
    } catch {}
  }

  const child = require('child_process').spawn(
    process.execPath,
    [path.join(__dirname, 'daemon-worker.js')],
    { detached: true, stdio: 'ignore', env: { ...process.env, AICP_PROJECT_PATH: projectPath } }
  );
  child.unref();
  console.log(`[daemon] Started (pid ${child.pid}), tracking: ${projectPath}`);
}

function stop() {
  const pid = readPid();
  if (!pid) { console.log('[daemon] Not running'); return; }
  try {
    process.kill(pid, 'SIGTERM');
    fs.unlinkSync(PID_FILE);
    console.log(`[daemon] Stopped (pid ${pid})`);
  } catch (e) {
    console.warn('[daemon] Could not stop:', e.message);
  }
}

function status() {
  const pid = readPid();
  const running = pid ? (() => { try { process.kill(pid, 0); return true; } catch { return false; } })() : false;
  const { pathToProjectFolder, findMatchingProjectFolder } = require('./log-scanner');
  const claudeFolder = pathToProjectFolder(PROJECT_PATH);
  const resolvedFolder = findMatchingProjectFolder(PROJECT_PATH);
  const matched = resolvedFolder !== null;
  const resolvedNote = matched && resolvedFolder !== claudeFolder ? ` (resolved to parent: ${resolvedFolder})` : '';
  console.log(`[daemon] Status:        ${running ? `running (pid ${pid})` : 'stopped'}`);
  console.log(`[daemon] Project path:  ${PROJECT_PATH}`);
  console.log(`[daemon] Claude folder: ${claudeFolder} ${matched ? `✔ found${resolvedNote}` : '✘ NOT FOUND in ~/.claude/projects'}`);
  if (!matched) {
    const claudeDir = path.join(os.homedir(), '.claude', 'projects');
    const available = fs.existsSync(claudeDir) ? fs.readdirSync(claudeDir).filter(e => fs.statSync(path.join(claudeDir, e)).isDirectory()) : [];
    console.log(`[daemon] Available:     ${available.join(', ')}`);
  }
  console.log(`[daemon] WAL pending:   ${wal.pendingCount()} records`);
  console.log(`[daemon] Log file:      ${path.join(CONFIG_DIR, 'daemon.log')}`);
}

module.exports = { start, stop, status, tick, PROJECT_PATH };
